def pre(i):
    """Return True iff i is a list of integers."""
    if not isinstance(i, list):
        return False
    return all(isinstance(x, int) for x in i)


def post(i, o):
    """Return True iff o is a correctly sorted version of i.

    Conditions:
    - o is a list.
    - o contains exactly the same multiset of elements as i.
    - o is non‑decreasing (ascending order, allowing duplicates).
    """
    if not isinstance(o, list):
        return False
    if len(i) != len(o):
        return False
    # multiset equality
    if sorted(i) != sorted(o):
        return False
    # non‑decreasing order
    return all(o[k] <= o[k + 1] for k in range(len(o) - 1))
